import{_ as a,o as e,c as l,a4 as r}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"长句表达套路","description":"","frontmatter":{},"headers":[],"relativePath":"biology/routine-expression.md","filePath":"biology/routine-expression.md"}'),i={name:"biology/routine-expression.md"};function o(n,t,s,h,d,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="长句表达套路" tabindex="-1">长句表达套路 <a class="header-anchor" href="#长句表达套路" aria-label="Permalink to &quot;长句表达套路&quot;">​</a></h1><p><strong>审题→找关键词→构建逻辑链→规范表述</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征" tabindex="-1">特征 <a class="header-anchor" href="#特征" aria-label="Permalink to &quot;特征&quot;">​</a></h3><ul><li>不是简单填空，需要完整句子</li><li>需要解释原因、分析机理</li><li>分值较高（2-3分）</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>&quot;原因是...&quot;</li><li>&quot;机理是...&quot;</li><li>&quot;为什么...&quot;</li><li>&quot;说明...&quot;</li><li>&quot;分析...&quot;</li></ul><hr><h2 id="二、答题策略" tabindex="-1">二、答题策略 <a class="header-anchor" href="#二、答题策略" aria-label="Permalink to &quot;二、答题策略&quot;">​</a></h2><h3 id="策略1-因果链条法" tabindex="-1">策略1：因果链条法 <a class="header-anchor" href="#策略1-因果链条法" aria-label="Permalink to &quot;策略1：因果链条法&quot;">​</a></h3><p><strong>结构</strong>：因为A，所以B，导致C</p><p><strong>示例</strong>：</p><ul><li>问：为什么光照增强，光合作用增强？</li><li>答：因为光照强度增强，所以光反应产生的[H]和ATP增多，导致暗反应中C₃的还原加快，从而光合作用增强</li></ul><h3 id="策略2-关键词定位法" tabindex="-1">策略2：关键词定位法 <a class="header-anchor" href="#策略2-关键词定位法" aria-label="Permalink to &quot;策略2：关键词定位法&quot;">​</a></h3><p><strong>找出题目和答案中的关键词</strong>：</p><ul><li>题目关键词：光照增强、光合作用</li><li>答案关键词：光反应、[H]、ATP、暗反应、C₃还原</li></ul><h3 id="策略3-分值对应法" tabindex="-1">策略3：分值对应法 <a class="header-anchor" href="#策略3-分值对应法" aria-label="Permalink to &quot;策略3：分值对应法&quot;">​</a></h3><p><strong>几分答几点</strong>：</p><ul><li>2分题：一般2个要点</li><li>3分题：一般3个要点</li></ul><hr><h2 id="三、常见类型及模板" tabindex="-1">三、常见类型及模板 <a class="header-anchor" href="#三、常见类型及模板" aria-label="Permalink to &quot;三、常见类型及模板&quot;">​</a></h2><h3 id="类型1-原因解释型" tabindex="-1">类型1：原因解释型 <a class="header-anchor" href="#类型1-原因解释型" aria-label="Permalink to &quot;类型1：原因解释型&quot;">​</a></h3><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当[条件]时，[过程]发生，使[结果]，因此[现象]。</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>问：为什么糖尿病患者会出现&quot;三多一少&quot;症状？</li><li>答：因为胰岛素分泌不足，组织细胞对葡萄糖的摄取、利用和储存减少，使血糖浓度升高，超过肾糖阈，葡萄糖随尿液排出（尿糖），带走大量水分（多尿）；细胞供能不足，引起饥饿感（多食）；能量供应不足，机体分解脂肪和蛋白质（消瘦）。</li></ul><hr><h3 id="类型2-机理分析型" tabindex="-1">类型2：机理分析型 <a class="header-anchor" href="#类型2-机理分析型" aria-label="Permalink to &quot;类型2：机理分析型&quot;">​</a></h3><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[物质/结构]通过[方式/过程]，导致[变化]，从而[结果]。</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>问：兴奋在突触处如何传递？</li><li>答：当兴奋传到突触前膜时，刺激突触小泡释放神经递质（乙酰胆碱等），神经递质经扩散通过突触间隙，与突触后膜上的特异性受体结合，引起突触后膜电位变化，从而使下一个神经元兴奋或抑制。</li></ul><hr><h3 id="类型3-实验结果分析型" tabindex="-1">类型3：实验结果分析型 <a class="header-anchor" href="#类型3-实验结果分析型" aria-label="Permalink to &quot;类型3：实验结果分析型&quot;">​</a></h3><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>由[结果1]可知[结论1]；由[结果2]可知[结论2]；综合以上结果，说明[总结论]。</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>问：实验结果显示，实验组细胞增殖速率明显低于对照组，说明什么？</li><li>答：说明该药物能抑制细胞增殖，可能通过抑制DNA复制或干扰细胞分裂过程发挥作用。</li></ul><hr><h3 id="类型4-比较分析型" tabindex="-1">类型4：比较分析型 <a class="header-anchor" href="#类型4-比较分析型" aria-label="Permalink to &quot;类型4：比较分析型&quot;">​</a></h3><p><strong>模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>与[对照组/正常情况]相比，[实验组/异常情况]的[指标]发生[变化]，原因是[机理分析]。</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>问：与正常植株相比，缺镁植株叶片发黄，为什么？</li><li>答：因为镁是叶绿素的组成元素，缺镁导致叶绿素合成受阻，而类胡萝卜素相对稳定，所以叶片呈现类胡萝卜素的黄色。</li></ul><hr><h2 id="四、高频考点及标准表述" tabindex="-1">四、高频考点及标准表述 <a class="header-anchor" href="#四、高频考点及标准表述" aria-label="Permalink to &quot;四、高频考点及标准表述&quot;">​</a></h2><h3 id="考点1-光合作用相关" tabindex="-1">考点1：光合作用相关 <a class="header-anchor" href="#考点1-光合作用相关" aria-label="Permalink to &quot;考点1：光合作用相关&quot;">​</a></h3><p><strong>光照增强→光合增强</strong>：</p><ul><li>光照强度增强，光反应产生的[H]和ATP增多，促进暗反应中C₃的还原，从而增强光合作用</li></ul><p><strong>CO₂浓度升高→光合增强</strong>：</p><ul><li>CO₂浓度升高，CO₂固定加快，C₃生成增多，在[H]和ATP充足的情况下，C₃还原加快，从而增强光合作用</li></ul><p><strong>C₃、C₅含量变化</strong>（光照增强）：</p><ul><li>[H]和ATP增多，C₃还原加快，C₃消耗增多而含量减少，C₅生成增多而含量增加</li></ul><hr><h3 id="考点2-呼吸作用相关" tabindex="-1">考点2：呼吸作用相关 <a class="header-anchor" href="#考点2-呼吸作用相关" aria-label="Permalink to &quot;考点2：呼吸作用相关&quot;">​</a></h3><p><strong>为什么剧烈运动后肌肉酸痛？</strong></p><ul><li>剧烈运动时，氧气供应不足，肌肉细胞进行无氧呼吸产生乳酸，乳酸积累刺激神经末梢，产生酸痛感</li></ul><hr><h3 id="考点3-遗传相关" tabindex="-1">考点3：遗传相关 <a class="header-anchor" href="#考点3-遗传相关" aria-label="Permalink to &quot;考点3：遗传相关&quot;">​</a></h3><p><strong>为什么近亲结婚会增加隐性遗传病的发病率？</strong></p><ul><li>近亲双方携带相同隐性致病基因的概率较高，结婚后子代隐性纯合（患病）的概率增加</li></ul><p><strong>为什么男色盲患者多于女色盲患者？</strong></p><ul><li>色盲是X染色体隐性遗传病，男性只有一条X染色体，只要携带致病基因就患病；女性有两条X染色体，只有两条都携带致病基因才患病</li></ul><hr><h3 id="考点4-调节相关" tabindex="-1">考点4：调节相关 <a class="header-anchor" href="#考点4-调节相关" aria-label="Permalink to &quot;考点4：调节相关&quot;">​</a></h3><p><strong>为什么二次免疫更快更强？</strong></p><ul><li>初次免疫时产生了记忆细胞，当相同抗原再次入侵时，记忆细胞能迅速增殖分化，快速产生大量抗体，所以二次免疫反应更快更强</li></ul><p><strong>为什么糖尿病患者容易感染？</strong></p><ul><li>糖尿病患者血糖浓度高，有利于细菌生长繁殖；同时高血糖可能影响白细胞功能，导致免疫力下降</li></ul><hr><h3 id="考点5-生态相关" tabindex="-1">考点5：生态相关 <a class="header-anchor" href="#考点5-生态相关" aria-label="Permalink to &quot;考点5：生态相关&quot;">​</a></h3><p><strong>为什么能量流动逐级递减？</strong></p><ul><li>每个营养级的能量大部分通过呼吸作用以热能形式散失，一部分流向分解者，一部分未被利用，只有10%-20%能流到下一营养级</li></ul><p><strong>为什么要保护生物多样性？</strong></p><ul><li>生物多样性具有直接价值（提供食物、药物等）、间接价值（生态功能）和潜在价值，保护生物多样性有利于维持生态系统稳定，促进可持续发展</li></ul><hr><h2 id="五、易错点提醒" tabindex="-1">五、易错点提醒 <a class="header-anchor" href="#五、易错点提醒" aria-label="Permalink to &quot;五、易错点提醒&quot;">​</a></h2><h3 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">错误类型</th><th style="text-align:center;">错误示例</th><th style="text-align:center;">正确表述</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>口语化</strong></td><td style="text-align:center;">&quot;植物吃不下饭&quot;</td><td style="text-align:center;">&quot;光合作用减弱，有机物合成减少&quot;</td></tr><tr><td style="text-align:center;"><strong>逻辑跳跃</strong></td><td style="text-align:center;">&quot;光照强，所以光合强&quot;</td><td style="text-align:center;">&quot;光照强，光反应产生[H]和ATP多，促进暗反应，光合强&quot;</td></tr><tr><td style="text-align:center;"><strong>关键词缺失</strong></td><td style="text-align:center;">&quot;酶让反应变快&quot;</td><td style="text-align:center;">&quot;酶降低化学反应的活化能，加快反应速率&quot;</td></tr><tr><td style="text-align:center;"><strong>因果颠倒</strong></td><td style="text-align:center;">&quot;血糖高导致胰岛素少&quot;</td><td style="text-align:center;">&quot;胰岛素少导致血糖高&quot;</td></tr></tbody></table><hr><h2 id="六、练习建议" tabindex="-1">六、练习建议 <a class="header-anchor" href="#六、练习建议" aria-label="Permalink to &quot;六、练习建议&quot;">​</a></h2><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li><strong>背模板</strong>：记住常见类型的答题模板</li><li><strong>看答案</strong>：学习标准答案的表述方式</li><li><strong>自己写</strong>：先自己组织语言，再对照答案修改</li><li><strong>提炼关键词</strong>：总结每类题目的关键词</li></ol><h3 id="检验标准" tabindex="-1">检验标准 <a class="header-anchor" href="#检验标准" aria-label="Permalink to &quot;检验标准&quot;">​</a></h3><ul><li>是否用了专业术语？</li><li>逻辑是否完整？</li><li>是否答出了所有得分点？</li></ul><hr><p><strong>文档编号</strong>: Bio-Review-Routine-004<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>',88)])])}const g=a(i,[["render",o]]);export{c as __pageData,g as default};
